/// @todo Size unknown.
struct ItemStateTable {
    /// @at{0} @sz{4}
    enum_t anim_id;

    /// @at{4} @sz{4}
    HSD_GObjPredicate animated;

    /// @at{8} @sz{4}
    HSD_GObjEvent physics_updated;

    /// @at{C} @sz{4}
